external_knowledge:
- "Top 3 universities" refers to the three universities with the highest minimum GPA requirements for admission, as determined by the descending order of GPA requirements.; 
- The query considers the GPA requirement as a key factor in determining the ranking of universities.; 
- The location details include the location name, state, and country.

sql:
SELECT outstate, avg_debt
FROM finances
ORDER BY outstate DESC;

SELECT AVG(outstate) AS avg_outstate, AVG(avg_debt) AS avg_student_debt
FROM finances
WHERE univ_id = 1;

SELECT grad_rate
FROM academics
WHERE phd > 50;
